name: Approve Workflows

on:
  pull_request_target:
    types:
      - labeled
      - synchronize
    branches:
      - main
      - 'release-**'

jobs:
  approve:
    runs-on: ubuntu-latest
    steps:
      - name: Approve pending workflows
        uses: actions/github-script@v7
        with:
          github-token: ${{ secrets.GITHUB_TOKEN }}
          script: |
            const owner = context.repo.owner;
            const repo = context.repo.repo;
            const headSha = context.payload.pull_request.head.sha;
            const author = context.payload.pull_request.user.login;
            const labels = context.payload.pull_request.labels.map(l => l.name);

            // List all PRs by the author to check if first-time contributor
            const { data: prs } = await github.rest.pulls.list({
              owner,
              repo,
              state: 'all',
              per_page: 100,
              creator: author
            });

            const isFirstTimeContributor = prs.length <= 1;
            const hasOkToTestLabel = labels.includes('ok-to-test');

            // Approve if not first-time contributor or has ok-to-test label
            if (!isFirstTimeContributor || hasOkToTestLabel) {
              // List workflow runs for the head SHA with status action_required
              const { data: runs } = await github.rest.actions.listWorkflowRunsForRepo({
                owner,
                repo,
                head_sha: headSha,
                status: 'action_required'
              });

              // Approve each action_required workflow run
              for (const run of runs.workflow_runs) {
                await github.rest.actions.approveWorkflowRun({
                  owner,
                  repo,
                  run_id: run.id
                });
                console.log(`Approved workflow run ${run.id}`);
              }
            } else {
              console.log('First-time contributor without ok-to-test label - skipping approval');
            }

